@app.post("/screenshot")
def screenshot():
    _ensure_bucket()
    ip = request.headers.get("X-Forwarded-For", request.remote_addr) or ""
    ip = ip.split(",")[0].strip() if ip else ""

    if not _rate_limit_ok(ip):
        return jsonify({"error": "rate_limited"}), 429

    payload = request.get_json(silent=True) or {}
    url = (payload.get("url") or "").strip()
    w = int(payload.get("width") or THUMB_WIDTH)
    h = int(payload.get("height") or THUMB_HEIGHT)
    ttl = int(payload.get("ttl_seconds") or DEFAULT_TTL_SECONDS)
    fmt = (payload.get("format") or IMAGE_FORMAT).lower()
    fullpage = bool(payload.get("fullpage") if payload.get("fullpage") is not None else FULLPAGE)

    w = _clamp(w, 64, 2000)
    h = _clamp(h, 64, 2000)
    ttl = _clamp(ttl, 60, MAX_TTL_SECONDS)
    if fmt not in ("jpeg", "png"):
        return jsonify({"error": "invalid_format"}), 400

    ok, err = _validate_url(url)
    if not ok:
        return jsonify({"error": err}), 400

    canon = _canonicalize_url(url)
    ck = _cache_key(canon, w, h, fullpage, fmt)
    key = _s3_key_for(ck, fmt)

    existing = _s3_head(S3_BUCKET, key)
    if existing is not None:
        if PUBLIC_READ:
            out_url = _public_url(S3_BUCKET, key)
            return jsonify(
                {
                    "url": canon,
                    "cache_key": ck,
                    "s3_bucket": S3_BUCKET,
                    "s3_key": key,
                    "image_url": out_url,
                    "cached": True,
                }
            )
        if RETURN_PRESIGNED_URLS:
            return jsonify(
                {
                    "url": canon,
                    "cache_key": ck,
                    "s3_bucket": S3_BUCKET,
                    "s3_key": key,
                    "image_url": _s3_presign(S3_BUCKET, key, S3_PRESIGN_SECONDS),
                    "cached": True,
                }
            )
        return jsonify({"url": canon, "cache_key": ck, "s3_bucket": S3_BUCKET, "s3_key": key, "cached": True})

    req_id = str(uuid.uuid4())
    start = time.time()
    try:
        png = _render(canon, fullpage=fullpage)
        img_bytes, content_type = _make_thumbnail(png, w, h, fmt)
        cache_control = f"public, max-age={ttl}" if (PUBLIC_READ or S3_ACL == "public-read") else f"max-age={ttl}"
        _s3_put(S3_BUCKET, key, img_bytes, content_type, cache_control)
    except Exception as e:
        log.exception("render_failed req_id=%s url=%s", req_id, canon)
        return jsonify({"error": "render_failed", "request_id": req_id, "detail": str(e)}), 500

    elapsed_ms = int((time.time() - start) * 1000)
    if PUBLIC_READ:
        out_url = _public_url(S3_BUCKET, key)
    elif RETURN_PRESIGNED_URLS:
        out_url = _s3_presign(S3_BUCKET, key, S3_PRESIGN_SECONDS)
    else:
        out_url = ""

    return jsonify(
        {
            "url": canon,
            "cache_key": ck,
            "s3_bucket": S3_BUCKET,
            "s3_key": key,
            "image_url": out_url,
            "cached": False,
            "request_id": req_id,
            "elapsed_ms": elapsed_ms,
            "width": w,
            "height": h,
            "format": fmt,
            "fullpage": fullpage,
        }
    )


if __name__ == "__main__":
    _ensure_bucket()
    app.run(host=APP_HOST, port=APP_PORT, threaded=True)